mapper.select:
SELECT po.product_option_id, GREATEST( po.stock - IFNULL(SUM( CASE WHEN sh.status = 'HOLD' AND sh.active_hold = 1 AND sh.expires_at > NOW() THEN sh.count ELSE 0 END ), 0), 0 ) AS available FROM nextjs_shop_product_option po JOIN nextjs_shop_product p ON p.product_id = po.product_id JOIN nextjs_shop_seller s ON s.seller_no = p.seller_no LEFT JOIN nextjs_shop_stock_hold sh ON sh.product_option_id = po.product_option_id WHERE s.approval_status = 'APPROVED' AND p.sale_stop = 0 AND po.product_option_id IN
#{id}
GROUP BY po.product_option_id

mapper.insert:
INSERT INTO nextjs_shop_stock_hold (user_no, product_option_id, cart_id, count, status, active_hold, expires_at, created_at, return_url) SELECT x.user_no, x.product_option_id, x.cart_id, x.count, 'HOLD', 1, DATE_ADD(NOW(), INTERVAL x.ttl_seconds SECOND), NOW(), x.return_url FROM (
SELECT #{r.userNo} AS user_no, #{r.productOptionId} AS product_option_id, #{r.cartId} AS cart_id, #{r.count} AS count, #{r.ttlSeconds} AS ttl_seconds, #{r.returnUrl} AS return_url
) x JOIN nextjs_shop_product_option po ON po.product_option_id = x.product_option_id JOIN nextjs_shop_product p ON p.product_id = po.product_id JOIN nextjs_shop_seller s ON s.seller_no = p.seller_no WHERE s.approval_status = 'APPROVED' AND p.sale_stop = 0 ON DUPLICATE KEY UPDATE cart_id = VALUES(cart_id), count = VALUES(count), expires_at = VALUES(expires_at), status = 'HOLD', active_hold = 1

mapper.select:
SELECT t.product_option_id, t.hold_id, t.count FROM nextjs_shop_stock_hold t INNER JOIN ( SELECT product_option_id, MAX(hold_id) AS max_id FROM nextjs_shop_stock_hold WHERE user_no = #{userNo} AND status = 'HOLD' AND active_hold = 1 AND expires_at > NOW() AND product_option_id IN
#{id}
AND status = 'HOLD' GROUP BY product_option_id ) m ON m.max_id = t.hold_id

