mapper.select:
SELECT MAX(created_at)
FROM nextjs_shop_stock_hold
WHERE user_no = #{userNo}

SELECT uc.user_coupon_id, c.coupon_id, c.description, c.discount_type, c.discount_value, c.max_discount, c.minimum_order_before_amount, c.is_stackable, c.is_product_restricted, c.amount, c.start_date, c.end_date, c.issue_method, ca.coupon_allowed_id, ca.product_id FROM nextjs_shop_user_coupon uc JOIN nextjs_shop_coupon c ON uc.coupon_id = c.coupon_id LEFT JOIN nextjs_shop_coupon_allowed ca ON ca.coupon_id = c.coupon_id AND ca.product_id IN
#{productId}
WHERE uc.user_no = #{userNo} AND uc.used = 0 AND c.seller_no IS NULL AND c.admin_no IS NOT NULL AND c.is_deleted = 0 AND c.status = 'ACTIVE' AND c.amount > 0 AND ( c.is_product_restricted = 0 OR ca.product_id IS NOT NULL ) AND ( c.issue_method = 'CLAIM' OR (c.issue_method IN ('MANUAL','AUTO') AND uc.user_coupon_id IS NOT NULL) )

SELECT uc.user_coupon_id, c.coupon_id, c.description, c.discount_type, c.discount_value, c.max_discount, c.minimum_order_before_amount, c.is_stackable, c.is_product_restricted, c.amount, c.start_date, c.end_date, c.issue_method, ca.coupon_allowed_id, ca.product_id, s.seller_name FROM nextjs_shop_user_coupon uc JOIN nextjs_shop_coupon c ON uc.coupon_id = c.coupon_id AND uc.used = 0 JOIN nextjs_shop_product p ON c.seller_no = p.seller_no AND p.product_id IN
#{productId}
LEFT JOIN nextjs_shop_coupon_allowed ca ON ca.coupon_id = c.coupon_id AND ca.product_id = p.product_id JOIN nextjs_shop_seller s ON c.seller_no = s.seller_no WHERE uc.user_no = #{userNo} AND c.is_deleted = 0 AND c.status = 'ACTIVE' AND c.amount > 0 AND ( c.is_product_restricted = 0 OR ca.product_id IS NOT NULL ) AND ( c.issue_method = 'CLAIM' OR (c.issue_method IN ('MANUAL','AUTO') AND uc.user_coupon_id IS NOT NULL) )

SELECT sh.hold_id, r.count, pd.product_option_id, IFNULL(pd.add_price, 0) AS addPrice, uc.user_coupon_id, p.product_id, p.origin_price, p.final_price, c.coupon_id, c.description, c.discount_type, c.discount_value, c.max_discount, c.minimum_order_before_amount, c.is_stackable, c.is_product_restricted FROM (
SELECT #{p.holdId} AS hold_id, #{p.productOptionId} AS product_option_id, #{p.count} AS count, #{p.couponId} AS coupon_id
) AS r JOIN nextjs_shop_stock_hold sh ON sh.hold_id = r.hold_id AND sh.product_option_id = r.product_option_id AND sh.user_no = #{userNo} AND sh.status = 'HOLD' AND sh.active_hold = 1 JOIN nextjs_shop_product_option pd ON pd.product_option_id = sh.product_option_id JOIN nextjs_shop_product p ON p.product_id = pd.product_id LEFT JOIN nextjs_shop_coupon c ON c.coupon_id = r.coupon_id AND c.status = 'Y' LEFT JOIN nextjs_shop_user_coupon uc ON c.coupon_id = uc.coupon_id AND uc.used = 0

